import DOM_SELECTORS from '../selectors/noticeSelectorsMap';
import useToggleDisplay from '../utils/useToggleDisplay';

const useNotice = () => {
    const { PRZELEWY24_NOTICE_MESSAGE } = DOM_SELECTORS;

    const { show, hide } = useToggleDisplay();

    const removeClassByPrefix = (element, prefix) => {
        const regx = new RegExp('\\b' + prefix + '.*?\\b', 'g');
        element.className = element.className.replace(regx, '');
        return element;
    }

    const hideNotice = (wrapper) => {
        const notice = document.querySelector(wrapper);
        const noticeMessage = notice.querySelector(PRZELEWY24_NOTICE_MESSAGE);

        if (!notice || !noticeMessage) {
            return;
        }

        noticeMessage.innerHTML = '';
        removeClassByPrefix(notice, 'alert-');
        hide(notice);
    }

    const showNotice = (wrapper, message, type) => {
        const notice = document.querySelector(wrapper);
        const noticeMessage = notice.querySelector(PRZELEWY24_NOTICE_MESSAGE);

        if (!notice || !noticeMessage) {
            return;
        }

        noticeMessage.innerHTML = message;
        notice.classList.add(`alert-${type}`);
        show(notice);
    }

    return {
        showNotice,
        hideNotice,
    }
}

export default useNotice;
