import useToggleDisplay from "./useToggleDisplay";
import useToggleLoader from "./useToggleLoader";
import useBodyScrollLock from "../utils/useBodyScrollLock";

const useModals = () => {
    const { show, hide } = useToggleDisplay();
    const { toggleLoader } = useToggleLoader();
    const { disableBodyScroll, enableBodyScroll } = useBodyScrollLock();

    const hideCardWhiteLabelModal = (targetElementSelector) => {
        const cardWhiteLabel = document.querySelector(targetElementSelector);

        enableBodyScroll();
        cardWhiteLabel && hide(cardWhiteLabel);
    }

    const showCardWhiteLabelModal = (targetElementSelector) => {
        const cardWhiteLabel = document.querySelector(targetElementSelector);

        disableBodyScroll();
        cardWhiteLabel && show(cardWhiteLabel);
    }

    const handleIframeClosure = (targetElementSelector, loaderSelector, urlReturn) => {
        const targetElement = document.querySelector(targetElementSelector);
        const iframe = targetElement?.querySelector("iframe");

        if (iframe) {
            iframe.remove();

            if (loaderSelector) {
                toggleLoader(loaderSelector, true);
            }

            setTimeout(() => {
                window.location.href = urlReturn;
            }, 2000);
        } else {
            console.warn('Iframe not found in the specified div.');
        }
    }

    return {
        hideCardWhiteLabelModal,
        showCardWhiteLabelModal,
        handleIframeClosure,
    }
}

export default useModals;
