import DOM_SELECTORS from "../selectors/applePaySelectorsMap";
import { getPayloadToUrl } from "../utils/urlHelpers";

import useForm from "../components/useForm";
import useToggleLoader from "../utils/useToggleLoader";
import useNotice from "../components/useNotice";
import useModals from "../utils/useModals";
import useToggleDisplay from "../utils/useToggleDisplay";
import paymentHelper from "../utils/usePaymentHelper";
import ApplePayService from "../services/ApplePayService";
import useOneClickPaymentHelper from "../utils/useOneClickPaymentHelper";

const applePayController = () => {
    let CardService = null;
    let APayService = null;
    let p24Notices = null;

    const {
        PRZELEWY24_APPLE_PAY_WRAPPER,
        PRZELEWY24_APPLE_PAY_NOTICE_WRAPPER,
        PRZELEWY24_APPLE_PAY_PAYMENT_INPUT,
        PRZELEWY24_APPLE_PAY_WHITE_LABEL_WRAPPER,
        PRZELEWY24_APPLE_PAY_WHITE_LABEL_LOADER,
        PRZELEWY24_APPLE_PAY_WHITE_LABEL_ID,
        PRZELEWY24_APPLE_PAY_SUBMIT_WRAPPER_LOADER,
        PRZELEWY24_APPLE_PAY_REGULATIONS_WRAPPER
    } = DOM_SELECTORS;

    const { toggle } = useToggleDisplay();
    const { getSelectedPaymentOption, getUrlFormFromPaymentOption, getRegulations } = paymentHelper();
    const { registerCardTransaction } = useForm();
    const { showNotice, hideNotice } = useNotice();
    const { toggleLoader } = useToggleLoader();
    const { showCardWhiteLabelModal, handleIframeClosure } = useModals();
    const { ensureAddressesAreSaved } = useOneClickPaymentHelper();

    const setCardWhiteLabelListeners = (urlReturn) => {
        CardService.onNeedInteraction = () => {
            toggleLoader(PRZELEWY24_APPLE_PAY_WHITE_LABEL_LOADER, false);
        }
        CardService.onNoNeedInteraction = () => {
            toggleLoader(PRZELEWY24_APPLE_PAY_WHITE_LABEL_LOADER, false);

            setTimeout(() => {
                handleIframeClosure(
                    PRZELEWY24_APPLE_PAY_WHITE_LABEL_WRAPPER,
                    PRZELEWY24_APPLE_PAY_WHITE_LABEL_LOADER,
                    urlReturn
                );
            }, 60000);
        }
        CardService.onSuccess = () => {
            handleIframeClosure(
                PRZELEWY24_APPLE_PAY_WHITE_LABEL_WRAPPER,
                PRZELEWY24_APPLE_PAY_WHITE_LABEL_LOADER,
                urlReturn
            );
        }
        CardService.onFailed = () => {
            console.error('Failed transaction from white label handler from Apple pay');

            handleIframeClosure(
                PRZELEWY24_APPLE_PAY_WHITE_LABEL_WRAPPER,
                PRZELEWY24_APPLE_PAY_WHITE_LABEL_LOADER,
                urlReturn
            );
        }
    }

    const loadCardWhiteLabel = async (token) => {
        await CardService.loadWhiteLabel(
            PRZELEWY24_APPLE_PAY_WHITE_LABEL_ID,
            token,
            () => showCardWhiteLabelModal(PRZELEWY24_APPLE_PAY_WHITE_LABEL_WRAPPER),
        );
    }

    const handleRegulationsChange = (event) => {
        const regulationsWrapper = event.target.closest(PRZELEWY24_APPLE_PAY_REGULATIONS_WRAPPER);
        const submitWrapper = document.querySelector(PRZELEWY24_APPLE_PAY_WRAPPER);

        if (!submitWrapper) return;

        const regulations = getRegulations(regulationsWrapper);
        const regulationsChecked = Object.values(regulations).every((value) => value);

        toggle(submitWrapper, regulationsChecked);
    }

    const handleRegisterCardTransaction = async (payload, url) => {
        let token, urlReturn, urlForm;
        const payloadUrl = getPayloadToUrl(payload);

        urlForm = url || getUrlFormFromPaymentOption(getSelectedPaymentOption());

        try {
            const response = await registerCardTransaction(urlForm, payloadUrl);

            if (response?.errors) {
                showNotice(PRZELEWY24_APPLE_PAY_NOTICE_WRAPPER, response?.errors, 'danger');
            } else {
                token = response?.token;
                urlReturn = response?.urlReturn;
            }
        } catch (errorResponse) {
            if (errorResponse.error) {
                console.error(errorResponse.error);
            } else {
                console.error(errorResponse);
            }

            showNotice(
                PRZELEWY24_APPLE_PAY_NOTICE_WRAPPER,
                p24Notices?.transactionError || 'Error while processing transaction.',
                'danger'
            );
        }

        return { token, urlReturn }
    }

    const handleCardWhiteLabelTransaction = async (payload, url = '') => {
        const { token, urlReturn } = await handleRegisterCardTransaction(payload, url);

        if (!token || !urlReturn) {
            console.error('Token or urlReturn is missing.');
            return;
        }

        setCardWhiteLabelListeners(urlReturn);
        await loadCardWhiteLabel(token);
    }

    const handleApplePaymentButtonClick = async () => {
        hideNotice(PRZELEWY24_APPLE_PAY_NOTICE_WRAPPER);

        // CRITICAL: Ensure addresses are saved before processing Apple Pay payment (module-aware)
        console.log('[Apple Pay] Checking if address saving is required for current checkout module...');
        const addressesSaved = await ensureAddressesAreSaved();

        if (!addressesSaved) {
            console.error('[Apple Pay] Cannot proceed - addresses are not saved or validation failed');
            showNotice(
                PRZELEWY24_APPLE_PAY_NOTICE_WRAPPER,
                p24Notices?.addressError || 'Please complete your address information before proceeding with payment.',
                'danger'
            );
            return;
        }

        console.log('[Apple Pay] Address requirements satisfied, proceeding with Apple Pay...');

        const { total, currency } = window._p24ConfigTokenization?.options?.paymentDetails || null;

        if (!total || !currency) {
            console.error('Error while getting payment details. Total or currency is missing.');
            showNotice(
                PRZELEWY24_APPLE_PAY_NOTICE_WRAPPER,
                p24Notices?.transactionError || 'Error while processing transaction.',
                'danger'
            );
            return;
        }

        APayService.setPaymentDetails(total, currency);
        await APayService.processPayment();

        if (APayService.hasError() || APayService.isCanceled()) {
            showNotice(PRZELEWY24_APPLE_PAY_NOTICE_WRAPPER, APayService.getError(), 'danger');
            return;
        }

        const paymentToken = APayService.getPaymentData();

        if (!paymentToken) {
            console.error('Error while getting payment data. Payment token is missing.');
            showNotice(
                PRZELEWY24_APPLE_PAY_NOTICE_WRAPPER,
                p24Notices?.transactionError || 'Error while processing transaction.',
                'danger'
            );
            return;
        }

        const submitWrapper = document.querySelector(PRZELEWY24_APPLE_PAY_WRAPPER);
        const regulationsWrapper = document.querySelector(PRZELEWY24_APPLE_PAY_REGULATIONS_WRAPPER);
        const url = submitWrapper?.dataset.url;
        const regulations = getRegulations(regulationsWrapper);

        const payload = {
            payload: paymentToken,
            ...regulations
        }

        toggleLoader(PRZELEWY24_APPLE_PAY_SUBMIT_WRAPPER_LOADER, true);

        await handleCardWhiteLabelTransaction(payload, url);

        toggleLoader(PRZELEWY24_APPLE_PAY_SUBMIT_WRAPPER_LOADER, false);
    }

    const addApplePayButton = () => {
        APayService.createPaymentButton(handleApplePaymentButtonClick);
    }

    const initApplePay = async () => {
        await APayService.init();
        const paymentAvailable = await APayService.isPaymentAvailable();

        if (!paymentAvailable) {
            console.log('Apple Pay is not available.');
            showNotice(
                PRZELEWY24_APPLE_PAY_NOTICE_WRAPPER,
                p24Notices?.applePayUnavailable || 'Apple Pay is not available.',
                'danger'
            );
            return;
        }

        console.log('Apple Pay is available.');
        addApplePayButton();
    }

    const attachEvents = () => {
        const regulationsWrapper = document.querySelector(PRZELEWY24_APPLE_PAY_REGULATIONS_WRAPPER);

        regulationsWrapper?.querySelectorAll('input[type="checkbox"]')?.forEach((input) => {
            input.removeEventListener('change', handleRegulationsChange);
            input.addEventListener('change', handleRegulationsChange);
        });
    }

    const init = async (P24CardService = null) => {
        const p24ConfigApplePay = window._p24ConfigTokenization || null;
        const applePayAvailable = document.querySelector(PRZELEWY24_APPLE_PAY_PAYMENT_INPUT);

        p24Notices = window.p24Notices || null;

        if (P24CardService && applePayAvailable && p24ConfigApplePay) {
            CardService = P24CardService;
            APayService = new ApplePayService(p24ConfigApplePay);

            if (!APayService) {
                console.error('Error while initializing CardService or APayService. Config is missing.');
                showNotice(
                    PRZELEWY24_APPLE_PAY_NOTICE_WRAPPER,
                    p24Notices?.serviceError || 'Error while loading card service.',
                    'danger'
                );
                return;
            }

            await initApplePay();
            attachEvents();
        } else if (applePayAvailable && (!P24CardService || !p24ConfigApplePay)) {
            console.error('Error while initializing CardService. Config or Apple payment is missing.');
            showNotice(
                PRZELEWY24_APPLE_PAY_NOTICE_WRAPPER,
                p24Notices?.serviceError || 'Error while loading Apple service.',
                'danger'
            );
        }
    }

    return { init }
}

export default applePayController;
