import DOM_SELECTORS from "../selectors/cardSelectorsMap";
import useDefaultPaymentSubmitToggle from "../components/useDefaultPaymentSubmitToggle";

const defaultPaymentSubmitController = () => {
    const { PAYMENT_OPTION_INPUT_NAME } = DOM_SELECTORS;
    const { handleDefaultPaymentSubmitToggle } = useDefaultPaymentSubmitToggle();

    const attachEvents = () => {
        document.querySelectorAll(`input[name="${PAYMENT_OPTION_INPUT_NAME}"]`)?.forEach((input) => {
            input.removeEventListener('change', handleDefaultPaymentSubmitToggle);
            input.addEventListener('change', handleDefaultPaymentSubmitToggle);
        });
    }

    const init = () => {
        handleDefaultPaymentSubmitToggle();
        attachEvents();
    };

    return {
        init,
    };
}

export default defaultPaymentSubmitController;
