import DOM_SELECTORS from '../selectors/cardSelectorsMap';
import DOM_SELECTORS_ONE_CLICK from '../selectors/oneClickSecetorsMap';
import useToggleDisplay from '../utils/useToggleDisplay';

const useDefaultPaymentSubmitToggle = () => {
    const { PRZELEWY24_ONE_CLICK_METHOD_INPUT } = DOM_SELECTORS_ONE_CLICK;
    const {
        PAYMENT_CONDITIONS_TO_APPROVE,
        PAYMENT_CONFIRMATION,
        PAYMENT_OPTION_INPUT_NAME
    } = DOM_SELECTORS;

    const { show, hide } = useToggleDisplay();

    const getPaymentId = (paymentOption) => {
        return paymentOption.id;
    }

    const getPaymentAdditionalInformationById = (id) => {
        return document.querySelector(`#${id}-additional-information`);
    }

    const getSelectedPaymentOption = () => {
        return document.querySelector(`input[name="${PAYMENT_OPTION_INPUT_NAME}"]:checked`);
    }

    const handleDefaultPaymentSubmitToggle = () => {
        const selectedPaymentOption = getSelectedPaymentOption();

        if (!selectedPaymentOption) {
            return;
        }

        const paymentOptionId = getPaymentId(selectedPaymentOption);
        const additionalInformation = getPaymentAdditionalInformationById(paymentOptionId);

        const oneClickAvailable = additionalInformation.querySelector(PRZELEWY24_ONE_CLICK_METHOD_INPUT);
        const conditionsToApprove = document.querySelector(PAYMENT_CONDITIONS_TO_APPROVE);
        const paymentConfirmation = document.querySelectorAll(PAYMENT_CONFIRMATION);

        if (oneClickAvailable) {
            conditionsToApprove && hide(conditionsToApprove);

            if (paymentConfirmation.length > 0) {
                paymentConfirmation.forEach((paymentConfirmation) => {
                    hide(paymentConfirmation);
                });
            }
        } else {
            conditionsToApprove && show(conditionsToApprove);

            if (paymentConfirmation.length > 0) {
                paymentConfirmation.forEach((paymentConfirmation) => {
                    show(paymentConfirmation);
                });
            }
        }
    }
    return {
        handleDefaultPaymentSubmitToggle
    }
}

export default useDefaultPaymentSubmitToggle;
