import { DOMReady } from "./utils/DOMHelpers";
import repaymentFormController from "./controller/repaymentFormController";
import defaultPaymentSubmitController from "./controller/defaultPaymentSubmitController";
import cardController from "./controller/cardController";
import googlePayController from "./controller/googlePayController";
import applePayController from "./controller/applePayController";
import blikController from "./controller/blikController";
import CardService from "./services/CardService";

DOMReady(async () => {
    const { init: initRepaymentForm } = repaymentFormController();
    const { init: initDefaultPaymentSubmitController } = defaultPaymentSubmitController();
    const { init: initCardController } = cardController();
    const { init: initGooglePayController } = googlePayController();
    const { init: initApplePayController } = applePayController();
    const { init: initBlikController } = blikController();

    let P24CardService = null;
    const p24ConfigTokenization = window._p24ConfigTokenization || null;

    if (p24ConfigTokenization) {
        P24CardService = new CardService(p24ConfigTokenization);
    }

    initRepaymentForm();
    initDefaultPaymentSubmitController();
    await initCardController(P24CardService);
    await initGooglePayController(P24CardService);
    await initApplePayController(P24CardService);
    initBlikController();
});
