import { loadExternalScript } from "../utils/loadExternalScript";
import { convertObjectValuesToStrings} from "../utils/urlHelpers";

const DOM_SELECTORS = {
    PRZELEWY24_CARD_TOKENIZER: 'przelewy24-card-tokenizer',
    PRZELEWY24_CARD_WHITE_LABEL: 'przelewy24-card-white-label',
}

class CardService {
    constructor(config) {
        const {
            merchantId,
            sessionId,
            sign,
            mode = 'sandbox',
            options,
            lang = 'pl'
        } = config;

        this.merchantId = merchantId;
        this.sessionId = sessionId;
        this.sign = sign;
        this.mode = mode;

        this.setOptions(options);
        this.options.lang = lang;

        this.tokenizer = null;
        this.tokenizerElement = DOM_SELECTORS.PRZELEWY24_CARD_TOKENIZER;
        this.whiteLabelElement = DOM_SELECTORS.PRZELEWY24_CARD_WHITE_LABEL;

        this.urlReturn = '';
        this.error = null;
        this.cardData = null;
        this.saveOneClick = false;

        this.setWhiteLabelListener();
    }

    setOptions(options) {
        if (typeof options === 'object') {
            this.options = options;
        } else if (typeof options === 'string') {
            try {
                this.options = JSON.parse(options);
            } catch (exception) {
                this.options = {};
            }
        } else {
            this.options = {};
        }
    }

    setWhiteLabelListener() {
        document.addEventListener('Przelewy24CardWhileLabelHandlerReady', () => this.initWhiteLabelHandler());
    }

    setSaveOneClick(value) {
        this.saveOneClick = value;
    }

    getWhiteLabelElement() {
        return document.getElementById(this.whiteLabelElement);
    }

    resetWhiteLabelIframe() {
        const container = this.getWhiteLabelElement();
        container && (container.innerHTML = '');
    }

    onSuccessTokenization() {
    }

    onFailedTokenization() {
    }

    initTokenizerHandler() {
        window.addEventListener('message', event => {
            const { data } = event;

            if (data?.type === 'start') {
                console.log('Start tokenizer on merchant site');
            }
            if (data?.type === 'ready') {
                console.log('Ready tokenizer on merchant site');
            }
            if (data?.type === 'success') {
                console.log('Success tokenizer on merchant site');
                this.onSuccessTokenization(data?.data);
            }
            if (data?.type === 'fail') {
                console.log('Fail tokenizer on merchant site');
                this.onFailedTokenization(data);
            }
            if (data?.action === 'error') {
                console.log('Error tokenizer on merchant site');
                this.onFailedTokenization(data);
            }
        });
    }

    onStart() {
    }

    onNeedInteraction() {
    }

    onNoNeedInteraction() {
    }

    onFailed() {
    }

    onSuccess() {
    }

    initWhiteLabelHandler() {
        Przelewy24CardWhileLabelHandler.config({
            'P24TargetElementId': this.whiteLabelElement,
            'P24CardWhiteLabelStartEventCallback': event => {
                console.log('Start on merchant site');
                console.log(event);
                this.onStart(event);
            },
            'P24NeedInteractionEventCallback': event => {
                console.log('Need interaction on merchant site');
                console.log(event);
                this.onNeedInteraction(event);
            },
            'P24DontNeedInteractionEventCallback': event => {
                console.log('Don\'t need interaction on merchant site');
                console.log(event);
                this.onNoNeedInteraction(event);
            },
            'P24ScriptFailedEventCallback': event => {
                console.log('Fail!');
                console.log(event);
                this.onFailed(event);
            },
            'P24ScriptSuccessfulEndsEventCallback': event => {
                console.log('Success!');
                console.log(event);
                this.onSuccess(event);
            }
        })

        Przelewy24CardWhileLabelHandler.main()
    }

    renderTokenizer() {
        this.tokenizer.render('form', `#${this.tokenizerElement}`, this.options);
    }

    onLoadTokenizer() {
        this.tokenizer = new Przelewy24CardTokenization(this.merchantId, this.sessionId, this.sign);
        this.renderTokenizer();
    }

    async loadTokenizer() {
        await loadExternalScript(
            'card-tokenizer-script',
            `https://${this.mode}.przelewy24.pl/js/cardTokenizationIframe.min.js?cms=presta&mid=${this.merchantId}&oc=${this.options.cards.one_click_card}&c2p=${this.options.c2p}`,
            () => this.onLoadTokenizer()
        );
    }

    async loadWhiteLabel(element = '', token = '', callback = () => {}) {
        this.whiteLabelElement = element || DOM_SELECTORS.PRZELEWY24_CARD_WHITE_LABEL;
        await loadExternalScript(
            'card-whitelabel-script',
            `https://${this.mode}.przelewy24.pl/whitelabel/card/javascript/${token}`,
            () => callback()
        );
    }

    async tokenize() {
        const mode = this.saveOneClick ? 'permanent' : 'temporary';
        const response = await this.tokenizer.tokenize(mode);
        const { errors = [], data } = response?.data || {};

        if (errors.length) {
            const [error] = errors;
            this.error = error;
        } else if (data) {
            this.cardData = data;
        }

        return !!data;
    }

    async prepareData() {
        this.resetWhiteLabelIframe();
        this.error = null;
        this.cardData = null;

        return await this.tokenize();
    }

    getError() {
        return this.error;
    }

    getPaymentData() {
        const paymentData = convertObjectValuesToStrings(this.cardData || {});

        return {
            ...paymentData,
        }
    }
}

export default CardService
