import DOM_SELECTORS from "../selectors/repaymentSelectorsMap";
import DOM_SELECTORS_PAYMENT_FORM from "../selectors/paymentFormSelectorsMap";
import useToggleDisplay from "../utils/useToggleDisplay";

const repaymentFormController = () => {
    const {
        PRZELEWY24_ADDITIONAL_INFORMATION,
        PRZELEWY24_PAYMENT_OPTION_FORM,
        PRZELEWY24_PAYMENT_INPUT,
        PRZELEWY24_REPAYMENT_SUBMIT,
    } = DOM_SELECTORS;

    const {
        PRZELEWY24_PAYMENT_OPTION_NESTED_INPUT,
        PAYMENT_OPTION_ADDITIONAL_INFORMATION,
        PAYMENT_OPTION_FORM,
        PAYMENT_OPTION_WRAPPER,
    } = DOM_SELECTORS_PAYMENT_FORM;

    const { show, hide, toggle } = useToggleDisplay();

    const hideElements = (elements) => {
        elements.forEach(element => hide(element));
    }

    const setSubmitButtonState = (state) => {
        const submitButton = document.querySelector(PRZELEWY24_REPAYMENT_SUBMIT);
        submitButton.disabled = !state;
    }

    const showActiveCollapseOptions = (paymentOptionId) => {
        const additionalInformation = document.querySelector(`${PRZELEWY24_ADDITIONAL_INFORMATION}[name="${paymentOptionId}"]`);
        const paymentOptionForm = document.querySelector(`${PRZELEWY24_PAYMENT_OPTION_FORM}[name="${paymentOptionId}"]`);

        additionalInformation && show(additionalInformation);
        paymentOptionForm && show(paymentOptionForm);
    }

    const hideCollapseOptions = () => {
        const additionalInformations = document.querySelectorAll(PRZELEWY24_ADDITIONAL_INFORMATION);
        const paymentOptionForms = document.querySelectorAll(PRZELEWY24_PAYMENT_OPTION_FORM);

        additionalInformations && hideElements(additionalInformations);
        paymentOptionForms && hideElements(paymentOptionForms);
    }

    const setFormAction = (form, url) => {
        form.action = url;
    }

    const getPaymentFormFromPaymentOptionId = (paymentOptionId) => {
        return document.querySelector(`${PRZELEWY24_PAYMENT_OPTION_FORM}[name="${paymentOptionId}"] form`);
    }

    const getSelectedPaymentOption = () => {
        return document.querySelector(PRZELEWY24_PAYMENT_INPUT + ':checked');
    }

    const getPaymentWrapperFromChild = (child) => {
        return child.closest(PAYMENT_OPTION_WRAPPER);
    }

    const getPaymentIdFromAdditionalInformationChild = (child) => {
        return child.closest(PAYMENT_OPTION_ADDITIONAL_INFORMATION).id.replace('-additional-information', '');
    }

    const getPaymentFormFromPaymentMethod = (paymentOption) => {
        const paymentId = getPaymentIdFromAdditionalInformationChild(paymentOption);
        const wrapper = getPaymentWrapperFromChild(paymentOption);

        return wrapper.querySelector(`${PAYMENT_OPTION_FORM}[id*="${paymentId}"] form`);
    }

    const handlePaymentNestedSwitch = (event) => {
        const paymentOption = event.currentTarget;
        const url = paymentOption.value;
        const form = getPaymentFormFromPaymentMethod(paymentOption);

        if (url && form) {
            setFormAction(form, url);
        }
    }

    const handlePaymentSwitch = () => {
        const selectedPaymentOption = getSelectedPaymentOption();
        const paymentOptionId = selectedPaymentOption?.id;

        if (!paymentOptionId) {
            setSubmitButtonState(false);
            return;
        }

        hideCollapseOptions();
        showActiveCollapseOptions(paymentOptionId);
        setSubmitButtonState(true);
    }

    const handleSubmitRepayment = () => {
        const selectedPaymentOption = getSelectedPaymentOption();
        const paymentOptionId = selectedPaymentOption?.id;

        if (!paymentOptionId) {
            return;
        }

        setSubmitButtonState(false);

        const form = getPaymentFormFromPaymentOptionId(paymentOptionId);

        if (form) {
            form.submit();
        } else {
            setSubmitButtonState(true);
        }
    }

    const attachEvents = () => {
        document.querySelectorAll(PRZELEWY24_PAYMENT_INPUT)?.forEach((input) => {
            input.removeEventListener('change', handlePaymentSwitch);
            input.addEventListener('change', handlePaymentSwitch);
        });

        document.querySelector(PRZELEWY24_REPAYMENT_SUBMIT)?.removeEventListener('click', handleSubmitRepayment);
        document.querySelector(PRZELEWY24_REPAYMENT_SUBMIT)?.addEventListener('click', handleSubmitRepayment);

        document.querySelectorAll(PRZELEWY24_PAYMENT_OPTION_NESTED_INPUT)?.forEach((input) => {
            input.removeEventListener('change', handlePaymentNestedSwitch);
            input.addEventListener('change', handlePaymentNestedSwitch);
        });
    }

    const init = () => {
        attachEvents();
    }

    return {
        init
    }
}

export default repaymentFormController;
