/**
 * Helper utility for integrating one-click payment methods with supported checkout modules
 * This provides a standardized way to ensure addresses are saved before processing
 * any one-click payment method (Google Pay, Apple Pay, BLIK, etc.)
 *
 * Supports: ETS One Page Checkout, Supercheckout (future)
 */

import useCheckoutModuleDetector from "./useCheckoutModuleDetector";
import useEtsAddressSaver from "./useEtsAddressSaver";
import useNotice from "../components/useNotice";

const useOneClickPaymentHelper = () => {
    const { detectCheckoutModule, hasOnePageCheckout, isEtsCheckout } = useCheckoutModuleDetector();
    const { showNotice } = useNotice();

    /**
     * Get the appropriate address saver based on detected checkout module
     * @returns {Object|null} - Address saver utility or null if not supported
     */
    const getAddressSaver = () => {
        const checkoutModule = detectCheckoutModule();

        switch (checkoutModule) {
            case 'ets_onepagecheckout':
                return useEtsAddressSaver();
            case 'supercheckout':
                // Will be implemented later
                // return useSupercheckoutAddressSaver();
                return null;
            default:
                return null;
        }
    };

    /**
     * Ensure addresses are saved before payment (module-agnostic)
     * @returns {Promise<boolean>} - True if addresses are ready for payment
     */
    const ensureAddressesAreSaved = async () => {
        if (!hasOnePageCheckout()) {
            console.log('[P24 One-Click Helper] No supported one-page checkout detected, skipping address validation');
            return true;
        }

        const addressSaver = getAddressSaver();

        if (!addressSaver) {
            console.warn('[P24 One-Click Helper] No address saver available for detected checkout module');
            return false;
        }

        return await addressSaver.ensureAddressesAreSaved();
    };

    return {
        ensureAddressesAreSaved
    };
};

export default useOneClickPaymentHelper;
